#include <bits/stdc++.h>
using namespace std;

const int N=1e5+10;

int n,q;
int dep[N],fa[N],sz[N],son[N],top[N],dfn[N],num;
int t[N<<2],tag[N<<2];
vector<int> e[N];

void dfs1(int x,int lst){
    fa[x]=lst;
    sz[x]=1,dep[x]=dep[lst]+1;
    for(int y:e[x]){
        dfs1(y,x);
        sz[x]+=sz[y];
        if(sz[y]>sz[son[x]])
            son[x]=y;
    }
}

void dfs2(int x,int topx){
    top[x]=topx;
    dfn[x]=++num;
    if(son[x])
        dfs2(son[x],topx);
    for(int y:e[x])
        if(y!=son[x])
            dfs2(y,y);
}

void pushdown(int cur,int l,int r){
    if(~tag[cur]){
        int mid=l+r>>1;
        tag[cur*2]=tag[cur*2+1]=tag[cur];
        t[cur*2]=tag[cur]*(mid-l+1);
        t[cur*2+1]=tag[cur]*(r-mid);
        tag[cur]=-1;
    }
}

void modify(int cur,int l,int r,int x,int y,int k){
    if(x<=l && r<=y){
        tag[cur]=k;
        t[cur]=k*(r-l+1);
        return;
    }
    pushdown(cur,l,r);
    int mid=l+r>>1;
    if(x<=mid) modify(cur*2,l,mid,x,y,k);
    if(y>mid) modify(cur*2+1,mid+1,r,x,y,k);
    t[cur]=t[cur*2]+t[cur*2+1];
}

int query(int cur,int l,int r,int x,int y){
    if(x<=l && r<=y)
        return t[cur];
    pushdown(cur,l,r);
    int mid=l+r>>1,res=0;
    if(x<=mid) res+=query(cur*2,l,mid,x,y);
    if(y>mid) res+=query(cur*2+1,mid+1,r,x,y);
    return res;
}

int main(){
    scanf("%d",&n);
    for(int i=2,f;i<=n;i++){
        scanf("%d",&f);
        e[f+1].push_back(i);
    }
    dfs1(1,0);
    dfs2(1,1);
    memset(tag,-1,sizeof(tag));
    scanf("%d",&q);
    char op[15];
    int x;
    while(q--){
        scanf("%s%d",op,&x);
        x++;
        if(*op=='i'){
            int ans=dep[x];
            for(;x;x=fa[top[x]]){
                ans-=query(1,1,n,dfn[top[x]],dfn[x]);
                modify(1,1,n,dfn[top[x]],dfn[x],1);
            }
            printf("%d\n",ans);
        }else{
            printf("%d\n",query(1,1,n,dfn[x],dfn[x]+sz[x]-1));
            modify(1,1,n,dfn[x],dfn[x]+sz[x]-1,0);
        }
    }
    return 0;
}
